        const lines = section.trim().split('\n');
        const npc = {};
        lines.forEach(line => {
          const parts = line.match(/^([^:]+):\s*(.*)$/);
          if (parts) {
            npc[parts[1].trim()] = parts[2].trim();
          }
        });
        if (!data[blockName]) data[blockName] = [];
        if (Object.keys(npc).length > 0) data[blockName].push(npc);
      });
      continue;
    }

          const items = {};
