          lines.forEach(line => {
            if (line.trim() === '') return;
            const parts = line.match(/^([^:]+):\s*(.*)$/);
            if (parts) {
              if (currentKey) items[currentKey] = currentValue.join('\n').trim();
              currentKey = parts[1].trim();
              currentValue = [parts[2].trim()];
            } else if (currentKey) {
              currentValue.push(line.trim());
            }
          });
          if (currentKey) items[currentKey] = currentValue.join('\n').trim();

          if (!data[blockName]) data[blockName] = [];
          data[blockName].push(items);
        }
        return data;
      }

