      // Hiển thị cửa hàng
      function renderMall(mallData) {
        const contentArea = document.getElementById('mall-content-area');
        if (!contentArea || !mallData || mallData.length === 0) return;
        // Cấu trúc mallData ví dụ: [{Sản phẩm: chuỗi bảng}]
        const mallRaw = mallData[0]['Sản phẩm'] || '';
        // Tách theo dòng
        const lines = mallRaw.split('\n').filter(Boolean);
        if (lines.length < 2) {
          contentArea.innerHTML = '<p>Định dạng dữ liệu cửa hàng sai</p>';
          return;
        }
        // Phân tích tiêu đề bảng
        const headerLine = lines[0].replace(/^\||\|$/g, '').split('|').map(h => h.trim());
        const rows = [];
        for (let i = 1; i < lines.length; i++) {
          if (!lines[i].startsWith('|')) continue;
          let rowCells = lines[i].replace(/^\||\|$/g, '').split('|').map(c => c.trim());
          if (rowCells.length === headerLine.length) rows.push(rowCells);
        }

        let html = `<table class="mall-table"><thead><tr>`;
        headerLine.forEach(h => {
          html += `<th>${h}</th>`;
        });
        html += `</tr></thead><tbody>`;
        rows.forEach(r => {
          html += `<tr>`;
          r.forEach(cell => html += `<td>${cell}</td>`);
          html += `</tr>`;
        });
        html += `</tbody></table>`;

        contentArea.innerHTML = html;
      }

      // Hiển thị thông tin rút thăm
      function renderLottery(lotteryData) {
        const contentArea = document.getElementById('lottery-content-area');
        if (!contentArea || !lotteryData) return;

        let html = '<div class="data-section">';
        lotteryData.forEach(item => {
          Object.entries(item).forEach(([key, value]) => {
            html += `<div class="data-item"><div class="data-key">${key}</div><div class="data-value">${value}</div></div>`;
          });
        });
        html += '</div>';
        contentArea.innerHTML = html;
      }

      // Khởi tạo trạng thái bảng gập (tất cả đều gập)
      function initCollapse() {
        const headers = document.querySelectorAll('.collapsible-header');
        headers.forEach(header => {
          const panel = header.nextElementSibling;
          panel.style.maxHeight = null;
          header.classList.remove('active');
          header.querySelector('.arrow').textContent = '▶';

          header.addEventListener('click', () => {
            const isActive = header.classList.contains('active');
            if (isActive) {
              panel.style.maxHeight = null;
              header.classList.remove('active');
              header.querySelector('.arrow').textContent = '▶';
            } else {
              panel.style.maxHeight = panel.scrollHeight + 'px';
              header.classList.add('active');
              header.querySelector('.arrow').textContent = '▼';
            }
          });
        });
      }

      // Luồng chính
      const rawText = dataContainer.textContent.trim();
      const parsedData = parseData(rawText);

      // Hiển thị dữ liệu tất cả các bảng
      if (parsedData['PlayerState'] && parsedData['PlayerState'].length > 0) {
        renderPlayerStatus(parsedData['PlayerState'][0]);
      }
      if (parsedData['QuestBoard']) {
        renderQuestBoard(parsedData['QuestBoard']);
      }
      if (parsedData['Mate']) {
        renderCompanionStatus(parsedData['Mate']);
      }
      if (parsedData['Mall']) {
        renderMall(parsedData['Mall']);
      }
      if (parsedData['Lottery']) {
        renderLottery(parsedData['Lottery']);
      }

      initCollapse();
    });
  </script>
